CREATE TABLE docs (id serial PRIMARY KEY, data jsonb);
CREATE INDEX ix_data_gin ON docs USING gin (data);
SELECT * FROM docs WHERE data @> '{"active":true}';

WITH RECURSIVE tree AS (
  SELECT id, parent, 1 lvl FROM nodes WHERE parent IS NULL
  UNION ALL
  SELECT n.id, n.parent, t.lvl+1 FROM nodes n JOIN tree t ON n.parent = t.id
)
SELECT * FROM tree;

-- B-tree (implicit) for equality/range
CREATE INDEX ix_orders_created ON orders (created_at);

-- GIN for jsonb containment & arrays
CREATE INDEX ix_docs_data ON docs USING gin (data jsonb_path_ops);

-- BRIN for a large, time-ordered table
CREATE INDEX ix_events_ts_brin ON events USING brin (event_time);

-- Manual maintenance
VACUUM (VERBOSE, ANALYZE) orders;

-- Tune autovacuum for a hot table
ALTER TABLE orders SET (
  autovacuum_vacuum_scale_factor = 0.02,
  autovacuum_vacuum_cost_limit = 2000
);

BEGIN ISOLATION LEVEL SERIALIZABLE;
  SELECT sum(amount) FROM accounts WHERE owner_id = 42;
  UPDATE accounts SET amount = amount - 100 WHERE id = 7;
COMMIT;
-- On error 40001 (serialization_failure): retry the whole transaction

CREATE TABLE posts (id serial PRIMARY KEY, tags text[]);
CREATE INDEX ix_posts_tags ON posts USING gin (tags);

-- Rows where tags contain both values
SELECT * FROM posts WHERE tags @> ARRAY['sql','postgres'];

-- Expand and aggregate
SELECT id, unnest(tags) AS tag FROM posts;
SELECT array_agg(DISTINCT t) FROM posts, unnest(tags) AS t;

ALTER TABLE articles
  ADD COLUMN tsv tsvector
  GENERATED ALWAYS AS (to_tsvector('english', title || ' ' || body)) STORED;
CREATE INDEX ix_articles_tsv ON articles USING gin (tsv);

SELECT id, ts_rank(tsv, q) AS rank
FROM articles, websearch_to_tsquery('english', 'postgres index') q
WHERE tsv @@ q
ORDER BY rank DESC;

CREATE TABLE events (
  id bigserial,
  event_time timestamptz NOT NULL,
  payload jsonb
) PARTITION BY RANGE (event_time);

CREATE TABLE events_2026_01 PARTITION OF events
  FOR VALUES FROM ('2026-01-01') TO ('2026-02-01');

-- Cheap retention: drop an old partition instead of DELETE
DROP TABLE events_2025_01;

CREATE MATERIALIZED VIEW daily_sales AS
SELECT date_trunc('day', created_at) AS day, sum(amount) AS total
FROM orders
GROUP BY 1;

CREATE UNIQUE INDEX ix_daily_sales_day ON daily_sales (day);

-- Refresh without blocking readers
REFRESH MATERIALIZED VIEW CONCURRENTLY daily_sales;

-- Preferred modern style
CREATE TABLE users (
  id bigint GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  email text NOT NULL
);

-- Legacy equivalent
CREATE TABLE legacy (id serial PRIMARY KEY);

SELECT nextval('users_id_seq');

-- CTE, reused twice and readable
WITH recent AS (
  SELECT * FROM orders WHERE created_at >= now() - interval '30 days'
)
SELECT count(*) FROM recent WHERE status = 'paid'
UNION ALL
SELECT count(*) FROM recent WHERE status = 'refunded';

-- Force materialization when reused expensively
WITH heavy AS MATERIALIZED (SELECT * FROM big_join_view) SELECT * FROM heavy;

CREATE EXTENSION IF NOT EXISTS btree_gist;
CREATE TABLE bookings (
  room_id int NOT NULL,
  during tstzrange NOT NULL,
  EXCLUDE USING gist (room_id WITH =, during WITH &&)
);
-- Rejects any overlapping booking for the same room

-- Roles & least privilege
CREATE ROLE app_read NOLOGIN;
GRANT SELECT ON ALL TABLES IN SCHEMA public TO app_read;
CREATE ROLE reporting LOGIN PASSWORD 'secret' IN ROLE app_read;

-- Inspect replication lag on the primary
SELECT client_addr, state, sent_lsn, replay_lsn
FROM pg_stat_replication;
